(function(){function init(){var form=document.querySelector('.hero-split form,form[data-name="hero-split-form"]');if(!form)return;if(form.dataset.cwdbHandoff==='1')return;form.dataset.cwdbHandoff='1';form.addEventListener('submit',function(ev){if(typeof form.checkValidity==='function' &&!form.checkValidity()){return;}ev.preventDefault();ev.stopPropagation();var zipEl=form.querySelector('input[name="zip" i]');var phoneEl=form.querySelector('input[name="phone" i]');var zip=zipEl?(zipEl.value || '').trim():'';var phone=phoneEl?(phoneEl.value || '').trim():'';if(phoneEl && phone.replace(/\D/g,'').length<10){if(phoneEl.setCustomValidity)phoneEl.setCustomValidity('Please enter a 10-digit phone number.');if(phoneEl.reportValidity)phoneEl.reportValidity();if(phoneEl.setCustomValidity){var clear=function(){phoneEl.setCustomValidity('');phoneEl.removeEventListener('input',clear);};phoneEl.addEventListener('input',clear);}return false;}var params;try{params=new URLSearchParams(window.location.search);}catch(e){params=new URLSearchParams();}if(zip)params.set('zip',zip);if(phone)params.set('phone',phone);var qs=params.toString();window.location.href='/get-a-quote' +(qs?'?' + qs:'');return false;},true);}if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',init);}else{init();}})();
